import java.util.Scanner;

public class BufferOverflowExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Vulnerable code - allocating fixed size buffer for storing the name
        byte[] buffer = new byte[10];

        // Copy the user input 'name' into the fixed size 'buffer'
        System.arraycopy(name.getBytes(), 0, buffer, 0, name.length());

        System.out.println("Hello, " + new String(buffer));
    }
}

