import java.util.Scanner;

public class SecureBufferExample {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Using StringBuilder to store user input safely
        StringBuilder safeBuffer = new StringBuilder();

        // Append the user input 'name' to the safe buffer
        safeBuffer.append(name);

        System.out.println("Hello, " + safeBuffer.toString());
    }
}

### Explanation:
취약유형: Buffer Overflow
